var suggestions=document.getElementById('suggestions'),search=document.getElementById('search');search!==null&&document.addEventListener('keydown',inputFocus);function inputFocus(a){a.ctrlKey&&a.key==='/'&&(a.preventDefault(),search.focus()),a.key==='Escape'&&(search.blur(),suggestions.classList.add('d-none'))}document.addEventListener('click',function(a){var b=suggestions.contains(a.target);b||suggestions.classList.add('d-none')}),document.addEventListener('keydown',suggestionFocus);function suggestionFocus(c){const d=suggestions.classList.contains('d-none');if(d)return;const a=[...suggestions.querySelectorAll('a')];if(a.length===0)return;const b=a.indexOf(document.activeElement);if(c.key==="ArrowUp"){c.preventDefault();const d=b>0?b-1:0;a[d].focus()}else if(c.key==="ArrowDown"){c.preventDefault();const d=b+1<a.length?b+1:b;a[d].focus()}}(function(){var a=new FlexSearch.Document({tokenize:"forward",cache:100,document:{id:'id',store:["href","title","description"],index:["title","description","content"]}});a.add({id:0,href:"/blog/nlp-series-part-3-word2vec-skipgram-subword/",title:"NLP Series [Part 3] · Word2Vec-SkipGram-SubWord",description:"In this notebook, we will train a Word2Vec skip-gram model for subword embeddings.",content:"Most of the steps are similar to our notebook on Word2Vec Skip-Gram model. The key change is that we will train a model on subword tokens so that we can generate embeddings for out of vocab words and have some tolerance for typos.\nThe first step for using any kind of NLP pipeline is to vectorize the text. Traditionally, we used to do this using one-hot representation of vectors. This had various downsides like:\n Vectors tend to be very long as their size depends on the vocabulary size of the corpus(which grows with the corpus size). They don\u0026rsquo;t have any understanding of the text. They are sparse and can\u0026rsquo;t be used for any comparison as any two one-hot encoded vector from a set will be orthogonal.  Word2vec is able to tackle all these challenges. The architecture we define later will enable us to learn a distributed representation for each word/token in our corpus. The key idea being, we can represent a word by adding contextual information to it. Context refers to the words/tokens neighbouring the word/token of interest to us.\nOf course this technique is not perfect and has it\u0026rsquo;s own downsides. The key downside being we loose the word/token ordering while training the word2vec model, hence we are essentially dealing with a bag of words model. This makes the resulting embeddings not suitable for sentence level representations. We will cover other techniques later (RNNs, Transformers) that produce embeddings more suitable for sentences. For now our sole focus will be learning good word/token level embeddings.\nFirst we will import the necessary libraries # from collections import Counter import re from typing import List, Tuple import numpy as np import requests from sklearn.metrics.pairwise import cosine_similarity import torch import torch.nn as nn from torch.utils.data import DataLoader, Dataset  The whole process of training the embeddings can be broken down into the following key steps:\n We define a class TextProcessor that has methods to pre-process the text. fetch_text() fetches the texts directly from urls containing our text data. process_text() applies basic pre-procesing steps to the text and creates tokens using white space tokenization. prepare_vocab() creates token to index mapping and vice versa. Create torch Dataset and Dataloader where each index in the dataset will be a tuple, (center_word_ix, context_word_ix); i.e. pairs of indices of center word and context based on a pre defined window size. Create our SkipGramModel model by defining a custom model on top of the torch.nn.Module. Define our loss function, optimizer and scheduler. Train the model for a certain number of epochs.  Finally, we will create a similarity matrix(cosine similarity) using the trained embeddings and explore similar embeddings for some word query.\nFetching and preparing the data # # We will be using the first four Harry Potter books. BASE_URL = \u0026quot;https://raw.githubusercontent.com/formcept/whiteboard/master/nbviewer/notebooks/data/harrypotter\u0026quot; BOOK_URLS = [ f\u0026quot;{BASE_URL}/Book%201%20-%20The%20Philosopher's%20Stone.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%202%20-%20The%20Chamber%20of%20Secrets.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%203%20-%20The%20Prisoner%20of%20Azkaban.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%204%20-%20The%20Goblet%20of%20Fire.txt\u0026quot; ]  class TextProcessor: def __init__(self, urls: List[str]): self.urls = urls def fetch_text(self): self.text = \u0026quot;\u0026quot; for i, url in enumerate(self.urls): r = requests.get(url) self.text += \u0026quot;\\n\\n\\n\u0026quot; + r.text print(f\u0026quot;Fetched {i+1}/{len(self.urls)} urls ...\u0026quot;) def process_text(self): print(\u0026quot;Processing text ...\u0026quot;) sentences = re.split(\u0026quot;\\n{2,}\u0026quot;, self.text) print(f\u0026quot;{len(sentences)} sentences\u0026quot;) self.clean_sentences = [] for txt in sentences: txt = txt.strip().lower() txt = txt.replace(\u0026quot;\\n\u0026quot;, \u0026quot;\u0026quot;) txt = \u0026quot; \u0026quot;.join(re.findall(\u0026quot;\\w+\u0026quot;, txt)) if txt: self.clean_sentences.append(txt) # Tokens and token counter will be used later to create a vocabulary for # us which will be used to map words/tokens to indices and vice versa, to # create training data and recreate the texts from predictions respectively. print(f\u0026quot;{len(sentences)} filtered sentences\u0026quot;) tokens = \u0026quot; \u0026quot;.join(self.clean_sentences).split(\u0026quot; \u0026quot;) print(f\u0026quot;{len(tokens)} tokens\u0026quot;) self.token_counter = Counter(tokens) print(f\u0026quot;{len(self.token_counter)} unique tokens\u0026quot;) def prepare_vocab(self, min_count: int): # min_count is the minimum number of times a token should appear in the # text to be considered in the vocabulary else they are assigned to a # default index which is equal to `len(vocab)`. self.w2ix = {} for i, (token, count) in enumerate( self.token_counter.most_common(len(self.token_counter)) ): if count \u0026lt; min_count: break else: self.w2ix[token] = i self.ix2w = {ix: w for w, ix in self.w2ix.items()} # Assign default index to rest of the tokens n = len(self.w2ix) for token, _ in self.token_counter.most_common(len(self.token_counter)): if token not in self.w2ix: self.w2ix[token] = n self.ix2w[n] = \u0026quot;\u0026lt;unk\u0026gt;\u0026quot; self.vocab_size = n + 1 print(f\u0026quot;Vocab size: {self.vocab_size}\u0026quot;)  text_processor = TextProcessor(BOOK_URLS)  text_processor.fetch_text() # Fetched 1/4 urls ... # Fetched 2/4 urls ... # Fetched 3/4 urls ... # Fetched 4/4 urls ...  text_processor.process_text() # Processing text ... # 20033 sentences # 20033 filtered sentences # 501854 tokens # 15078 unique tokens  text_processor.prepare_vocab(min_count=20) # Vocab size: 2103  Along with the TextProcessor we will also create a SubWordTextProcessor this time. The key method we introduce is _get_subword_tokens which takes a token and creates subword tokens from it.\nFor example:\n _get_subword_tokens(\u0026quot;harry\u0026quot;, 3, 6) returns {\u0026lsquo;arr\u0026rsquo;, \u0026lsquo;arry\u0026rsquo;, \u0026lsquo;har\u0026rsquo;, \u0026lsquo;harr\u0026rsquo;, \u0026lsquo;harry\u0026rsquo;, \u0026lsquo;rry\u0026rsquo;}. _get_subword_tokens(\u0026quot;wizard\u0026quot;, 3, 6) returns {\u0026lsquo;ard\u0026rsquo;, \u0026lsquo;iza\u0026rsquo;, \u0026lsquo;izar\u0026rsquo;, \u0026lsquo;izard\u0026rsquo;, \u0026lsquo;wiz\u0026rsquo;, \u0026lsquo;wiza\u0026rsquo;, \u0026lsquo;wizar\u0026rsquo;, \u0026lsquo;zar\u0026rsquo;, \u0026lsquo;zard\u0026rsquo;}.  class SubWordTextProcessor: def __init__(self, urls: List[str]): self.urls = urls self.max_subtoken_len = 0 def fetch_text(self): self.text = \u0026quot;\u0026quot; for i, url in enumerate(self.urls): r = requests.get(url) r.status_code self.text += \u0026quot;\\n\\n\\n\u0026quot; + r.text print(f\u0026quot;Fetched {i+1}/{len(self.urls)} urls ...\u0026quot;) def process_text(self, minn: int=3, maxn: int=6): print(\u0026quot;Processing text ...\u0026quot;) sentences = re.split(\u0026quot;\\n{2,}\u0026quot;, self.text) print(f\u0026quot;{len(sentences)} sentences\u0026quot;) self.clean_sentences = [] for txt in sentences: txt = txt.strip().lower() txt = txt.replace(\u0026quot;\\n\u0026quot;, \u0026quot;\u0026quot;) txt = \u0026quot; \u0026quot;.join(re.findall(\u0026quot;\\w+\u0026quot;, txt)) if txt: self.clean_sentences.append(txt) print(f\u0026quot;{len(sentences)} filtered sentences\u0026quot;) tokens = \u0026quot; \u0026quot;.join(self.clean_sentences).split(\u0026quot; \u0026quot;) print(f\u0026quot;{len(tokens)} tokens\u0026quot;) # sub word tokens self.subword_tokens = set() for token in tokens: self.subword_tokens.update(self._get_subword_tokens(token, minn, maxn)) print(f\u0026quot;{len(self.subword_tokens)} unique tokens\u0026quot;) def _get_subword_tokens(self, token: str, minn: int, maxn: int) -\u0026gt; List[str]: subword_tokens = [] n = len(token) for i in range(minn, maxn): if n \u0026lt;= i: subword_tokens.append(token) continue for j in range(n-i+1): subword_tokens.append(token[j:j+i]) result = set(subword_tokens) if len(result) \u0026gt; self.max_subtoken_len: self.max_subtoken_len = len(result) print(f\u0026quot;new token with max len: {token}\u0026quot;) return result def prepare_vocab(self): self.w2ix = {w: i+1 for i, w in enumerate(self.subword_tokens)} self.ix2w = {ix: w for w, ix in self.w2ix.items()} self.vocab_size = len(self.w2ix) + 1 print(f\u0026quot;Vocab size: {self.vocab_size}\u0026quot;) print(f\u0026quot;Max SubToken length: {self.max_subtoken_len}\u0026quot;)  subword_text_processor = SubWordTextProcessor(BOOK_URLS)  subword_text_processor.fetch_text() # Fetched 1/4 urls ... # Fetched 2/4 urls ... # Fetched 3/4 urls ... # Fetched 4/4 urls ...  subword_text_processor.process_text() # Processing text ... # 20033 sentences # 20033 filtered sentences # 501854 tokens # new token with max len: the # new token with max len: lived # new token with max len: dursley # new token with max len: perfectly # new token with max len: mysterious # new token with max len: philosophers # new token with max len: knickerbockers # new token with max len: transfiguration # new token with max len: enthusiastically # new token with max len: indistinguishable # new token with max len: uncharacteristically # 38494 unique tokens  subword_text_processor.prepare_vocab() # Vocab size: 38495 # Max SubToken length: 51  Preparing the torch Dataset and Dataloader # The Dataloader will enable us to send data in batches during the forward pass of the model training.\nclass HarryPotterDataset(Dataset): def __init__(self, text_processor: TextProcessor, subword_text_processor: SubWordTextProcessor, window_size: int=3): self.data = [] for txt in text_processor.clean_sentences: splits = txt.split(\u0026quot; \u0026quot;) for i in range(window_size, len(splits) -1): center_word = splits[i] window_words = splits[i-window_size:i]+splits[i+1:i+window_size+1] for context in window_words: subword_tokens = subword_text_processor._get_subword_tokens(center_word, 3, 6) subword_ixs = [subword_text_processor.w2ix[token] for token in subword_tokens] if len(subword_ixs) \u0026lt; subword_text_processor.max_subtoken_len: subword_ixs += [0] * (subword_text_processor.max_subtoken_len - len(subword_ixs)) self.data.append((subword_ixs, text_processor.w2ix[context])) def __getitem__(self, ix: int): return self.data[ix] def __len__(self): return len(self.data)  The Dataset essentially contains indexes of pairs of subwords(from the center word) and a context word.\ndataset = HarryPotterDataset(text_processor, subword_text_processor, 3)  len(dataset) # 2489461  def collate_fn(collate_fn_input: List[Tuple]): return ( torch.LongTensor([i[0] for i in collate_fn_input]), # sub words torch.LongTensor([i[1] for i in collate_fn_input]), # context word )  dataloader = DataLoader(dataset, batch_size=32, collate_fn=collate_fn, shuffle=True)  Creating the Word2Vec model using torch.nn.Module. # class SkipGramModel(nn.Module): def __init__(self, subword_vocab_size: int, vocab_size: int, embedding_size: int=50): super().__init__() self.embedding = nn.Embedding(subword_vocab_size, embedding_size) self.linear = nn.Linear(embedding_size, vocab_size) def forward(self, x): self.subword_embeddings = self.embedding(x) self.flat_embedding = torch.sum(self.subword_embeddings, dim=1) norm = torch.linalg.norm(self.flat_embedding, dim=1).view(-1, 1) self.flat_embedding = self.flat_embedding / norm return self.linear(self.flat_embedding)  The model architecure is Embeddings -\u0026gt; torch.sum(dim=1) -\u0026gt; Normalization -\u0026gt; Linear -\u0026gt; Softmax.\nEmbedding is nothing but \u0026ldquo;A simple lookup table that stores embeddings of a fixed dictionary and size\u0026rdquo; as mentioned in the pytorch documentation.\nBased on our model architecture, this layer will contain the trained sub word/token embeddings of interest to us and we will discard the weight matrix from the Linear layer.\nIn each forward pass we:\n Pass indexes of sub words/tokens(from the center word) as input x. These indexes are looked up in the self.embedding table. We sum up the all the sub word embeddings to create a single embedding. Normalize the embedding. We transform the embedding from last step using the Linear layer to get another vector with dimension vocab_size. Finally we apply softmax and calcualte loss.  A trained model should output high values for the context indices for a given center word.\ndevice = torch.device(\u0026quot;cuda\u0026quot; if torch.cuda.is_available() else \u0026quot;cpu\u0026quot;) model = SkipGramModel( subword_text_processor.vocab_size, text_processor.vocab_size, embedding_size=30 ).to(device)  Defining our loss function, optimizer and scheduler # criterion = nn.CrossEntropyLoss() optimizer = torch.optim.Adam(model.parameters(), lr=0.005) scheduler = torch.optim.lr_scheduler.StepLR(optimizer, step_size=5, gamma=0.5)  N_EPOCHS = 15 STEP_TO_LOG = 10000  Step 5. Train the model. # epoch_losses = [] batch_losses = [] for epoch in range(N_EPOCHS): losses = [] for i, data in enumerate(dataloader): inputs = data[0].to(device) outputs = data[1].to(device) pred = model(inputs) loss = criterion(pred, outputs) losses.append(loss.item()) loss.backward() optimizer.step() optimizer.zero_grad() if i % STEP_TO_LOG == 0: print(f\u0026quot;epoch {epoch + 1}; steps={i:\u0026gt;5}/{len(dataloader)}; loss={loss:\u0026lt;.5f}\u0026quot;) scheduler.step() batch_losses += losses epoch_losses.append(np.mean(losses)) print(f\u0026quot;epoch {epoch + 1} ; lr={scheduler._last_lr[0]}; loss={epoch_losses[-1]:\u0026lt;.5f}\\n\u0026quot;)  epoch 1; steps= 0/77796; loss=7.69866 epoch 1; steps=10000/77796; loss=5.52718 epoch 1; steps=20000/77796; loss=5.50602 epoch 1; steps=30000/77796; loss=5.16074 epoch 1; steps=40000/77796; loss=5.57408 epoch 1; steps=50000/77796; loss=5.57619 epoch 1; steps=60000/77796; loss=5.96200 epoch 1; steps=70000/77796; loss=5.40732 epoch 1 ; lr=0.005; loss=5.57117 epoch 2; steps= 0/77796; loss=6.06756 epoch 2; steps=10000/77796; loss=4.90114 epoch 2; steps=20000/77796; loss=5.68610 epoch 2; steps=30000/77796; loss=5.03594 epoch 2; steps=40000/77796; loss=5.15513 epoch 2; steps=50000/77796; loss=5.45436 epoch 2; steps=60000/77796; loss=5.79112 epoch 2; steps=70000/77796; loss=6.19790 epoch 2 ; lr=0.005; loss=5.48046 epoch 3; steps= 0/77796; loss=5.92790 epoch 3; steps=10000/77796; loss=5.60727 epoch 3; steps=20000/77796; loss=5.48967 epoch 3; steps=30000/77796; loss=4.62533 epoch 3; steps=40000/77796; loss=6.08401 epoch 3; steps=50000/77796; loss=4.74142 epoch 3; steps=60000/77796; loss=4.95852 epoch 3; steps=70000/77796; loss=4.99557 epoch 3 ; lr=0.005; loss=5.45876 epoch 4; steps= 0/77796; loss=4.75198 epoch 4; steps=10000/77796; loss=5.95619 epoch 4; steps=20000/77796; loss=5.41328 epoch 4; steps=30000/77796; loss=4.87488 epoch 4; steps=40000/77796; loss=5.22511 epoch 4; steps=50000/77796; loss=5.46653 epoch 4; steps=60000/77796; loss=5.32700 epoch 4; steps=70000/77796; loss=5.57476 epoch 4 ; lr=0.005; loss=5.44721 epoch 5; steps= 0/77796; loss=5.29591 epoch 5; steps=10000/77796; loss=5.17287 epoch 5; steps=20000/77796; loss=4.68313 epoch 5; steps=30000/77796; loss=5.24046 epoch 5; steps=40000/77796; loss=5.01978 epoch 5; steps=50000/77796; loss=5.50917 epoch 5; steps=60000/77796; loss=5.78620 epoch 5; steps=70000/77796; loss=5.37485 epoch 5 ; lr=0.0025; loss=5.43968 epoch 6; steps= 0/77796; loss=5.60345 epoch 6; steps=10000/77796; loss=5.18261 epoch 6; steps=20000/77796; loss=5.32242 epoch 6; steps=30000/77796; loss=4.92906 epoch 6; steps=40000/77796; loss=5.45448 epoch 6; steps=50000/77796; loss=5.42371 epoch 6; steps=60000/77796; loss=6.04258 epoch 6; steps=70000/77796; loss=5.36360 epoch 6 ; lr=0.0025; loss=5.40934 epoch 7; steps= 0/77796; loss=5.80527 epoch 7; steps=10000/77796; loss=5.78214 epoch 7; steps=20000/77796; loss=5.39172 epoch 7; steps=30000/77796; loss=5.55385 epoch 7; steps=40000/77796; loss=5.24371 epoch 7; steps=50000/77796; loss=5.77154 epoch 7; steps=60000/77796; loss=5.71066 epoch 7; steps=70000/77796; loss=5.61069 epoch 7 ; lr=0.0025; loss=5.40635 epoch 8; steps= 0/77796; loss=5.99052 epoch 8; steps=10000/77796; loss=5.15616 epoch 8; steps=20000/77796; loss=5.66678 epoch 8; steps=30000/77796; loss=5.52756 epoch 8; steps=40000/77796; loss=5.32611 epoch 8; steps=50000/77796; loss=5.16439 epoch 8; steps=60000/77796; loss=5.85663 epoch 8; steps=70000/77796; loss=5.30744 epoch 8 ; lr=0.0025; loss=5.40491 epoch 9; steps= 0/77796; loss=5.77645 epoch 9; steps=10000/77796; loss=6.18814 epoch 9; steps=20000/77796; loss=5.33566 epoch 9; steps=30000/77796; loss=4.90566 epoch 9; steps=40000/77796; loss=5.76252 epoch 9; steps=50000/77796; loss=5.58853 epoch 9; steps=60000/77796; loss=4.98004 epoch 9; steps=70000/77796; loss=4.96006 epoch 9 ; lr=0.0025; loss=5.40365 epoch 10; steps= 0/77796; loss=5.77894 epoch 10; steps=10000/77796; loss=4.51202 epoch 10; steps=20000/77796; loss=5.37260 epoch 10; steps=30000/77796; loss=5.78464 epoch 10; steps=40000/77796; loss=5.84577 epoch 10; steps=50000/77796; loss=4.81790 epoch 10; steps=60000/77796; loss=5.44874 epoch 10; steps=70000/77796; loss=5.45955 epoch 10 ; lr=0.00125; loss=5.40228 epoch 11; steps= 0/77796; loss=5.82560 epoch 11; steps=10000/77796; loss=5.53803 epoch 11; steps=20000/77796; loss=5.24014 epoch 11; steps=30000/77796; loss=5.22756 epoch 11; steps=40000/77796; loss=5.47227 epoch 11; steps=50000/77796; loss=5.80264 epoch 11; steps=60000/77796; loss=5.13528 epoch 11; steps=70000/77796; loss=5.72560 epoch 11 ; lr=0.00125; loss=5.38614 epoch 12; steps= 0/77796; loss=5.19279 epoch 12; steps=10000/77796; loss=5.27793 epoch 12; steps=20000/77796; loss=5.21549 epoch 12; steps=30000/77796; loss=5.12911 epoch 12; steps=40000/77796; loss=5.25278 epoch 12; steps=50000/77796; loss=4.94656 epoch 12; steps=60000/77796; loss=5.58867 epoch 12; steps=70000/77796; loss=5.02581 epoch 12 ; lr=0.00125; loss=5.38483 epoch 13; steps= 0/77796; loss=5.11096 epoch 13; steps=10000/77796; loss=5.89121 epoch 13; steps=20000/77796; loss=5.49311 epoch 13; steps=30000/77796; loss=5.19873 epoch 13; steps=40000/77796; loss=4.61157 epoch 13; steps=50000/77796; loss=5.43000 epoch 13; steps=60000/77796; loss=5.41656 epoch 13; steps=70000/77796; loss=5.63828 epoch 13 ; lr=0.00125; loss=5.38434 epoch 14; steps= 0/77796; loss=5.76506 epoch 14; steps=10000/77796; loss=6.29965 epoch 14; steps=20000/77796; loss=5.04774 epoch 14; steps=30000/77796; loss=5.31003 epoch 14; steps=40000/77796; loss=5.34939 epoch 14; steps=50000/77796; loss=5.58271 epoch 14; steps=60000/77796; loss=4.87815 epoch 14; steps=70000/77796; loss=5.44520 epoch 14 ; lr=0.00125; loss=5.38391 epoch 15; steps= 0/77796; loss=4.82815 epoch 15; steps=10000/77796; loss=4.96780 epoch 15; steps=20000/77796; loss=5.07577 epoch 15; steps=30000/77796; loss=5.28820 epoch 15; steps=40000/77796; loss=5.67705 epoch 15; steps=50000/77796; loss=4.91246 epoch 15; steps=60000/77796; loss=4.38888 epoch 15; steps=70000/77796; loss=5.37233 epoch 15 ; lr=0.000625; loss=5.38342  weights = model.embedding.weight.detach().cpu().numpy() weights.shape # (38495, 30)  Creating the similarity matrix # embeddings = [] for token in list(text_processor.ix2w.values())[:-1]: tokens = subword_text_processor._get_subword_tokens(token, 3, 6) ixs = [subword_text_processor.w2ix[w] for w in tokens] embedding = np.sum([weights[ix] for ix in ixs], axis=0) embedding = embedding / np.linalg.norm(embedding) embeddings.append(embedding) embeddings = np.array(embeddings) embeddings.shape # (2102, 30)  similarity = cosine_similarity(embeddings, embeddings)  keys = list(text_processor.ix2w.values())[:-1]  def get_similar_words(input_word: str, n: int): if input_word not in text_processor.w2ix: print(\u0026quot;word not in vocab\u0026quot;) tokens = subword_text_processor._get_subword_tokens(input_word, 3, 6) ixs = [subword_text_processor.w2ix[w] for w in tokens if w in subword_text_processor.w2ix] embedding = np.sum([weights[ix] for ix in ixs], axis=0) embedding = embedding / np.linalg.norm(embedding) similarity_vector = cosine_similarity(embeddings, embedding.reshape(1, -1)).T[0] else: input_word_ix = text_processor.w2ix[input_word] similarity_vector = similarity[input_word_ix] most_similar_ixs = np.argsort(similarity_vector)[-n:][::-1] most_similar_words = [(keys[ix], similarity_vector[ix]) for ix in most_similar_ixs] for word, score in most_similar_words: print(f\u0026quot; \u0026gt; {word}, score={score: .2f}\u0026quot;)  Exploring similar embeddings for some queries \u0026hellip; # get_similar_words(\u0026quot;snape\u0026quot;, 10)   \u0026gt; snape, score= 1.00 \u0026gt; dumbledore, score= 0.92 \u0026gt; hagrid, score= 0.89 \u0026gt; snap, score= 0.86 \u0026gt; lupin, score= 0.84 \u0026gt; quirrell, score= 0.83 \u0026gt; moody, score= 0.81 \u0026gt; him, score= 0.80 \u0026gt; filch, score= 0.80 \u0026gt; lockhart, score= 0.78  # Typo get_similar_words(\u0026quot;snaoe\u0026quot;, 10)  word not in vocab \u0026gt; him, score= 0.86 \u0026gt; snap, score= 0.86 \u0026gt; hagrid, score= 0.81 \u0026gt; harry, score= 0.79 \u0026gt; it, score= 0.77 \u0026gt; snape, score= 0.77 \u0026gt; scabbers, score= 0.75 \u0026gt; them, score= 0.75 \u0026gt; quirrell, score= 0.71 \u0026gt; buckbeak, score= 0.71  # Typo get_similar_words(\u0026quot;snapi\u0026quot;, 10)  word not in vocab \u0026gt; snap, score= 0.95 \u0026gt; snape, score= 0.80 \u0026gt; peeves, score= 0.75 \u0026gt; hagrid, score= 0.74 \u0026gt; him, score= 0.74 \u0026gt; hermione, score= 0.73 \u0026gt; them, score= 0.72 \u0026gt; quirrell, score= 0.71 \u0026gt; dumbledore, score= 0.71 \u0026gt; lupin, score= 0.71  get_similar_words(\u0026quot;wizard\u0026quot;, 10)   \u0026gt; wizard, score= 1.00 \u0026gt; witch, score= 0.78 \u0026gt; powerful, score= 0.77 \u0026gt; old, score= 0.76 \u0026gt; strange, score= 0.75 \u0026gt; self, score= 0.75 \u0026gt; muggle, score= 0.73 \u0026gt; unpleasant, score= 0.70 \u0026gt; girl, score= 0.70 \u0026gt; extraordinary, score= 0.69  # Typo/OOV get_similar_words(\u0026quot;bizard\u0026quot;, 10)  word not in vocab \u0026gt; weird, score= 0.78 \u0026gt; effect, score= 0.78 \u0026gt; perfect, score= 0.75 \u0026gt; behavior, score= 0.75 \u0026gt; ordinary, score= 0.74 \u0026gt; creature, score= 0.74 \u0026gt; obvious, score= 0.73 \u0026gt; wonderful, score= 0.73 \u0026gt; spell, score= 0.72 \u0026gt; important, score= 0.72  # Typo/OOV get_similar_words(\u0026quot;durmstrang\u0026quot;, 10)   \u0026gt; durmstrang, score= 1.00 \u0026gt; beauxbatons, score= 0.88 \u0026gt; ghosts, score= 0.75 \u0026gt; students, score= 0.74 \u0026gt; among, score= 0.72 \u0026gt; carriage, score= 0.70 \u0026gt; hufflepuffs, score= 0.70 \u0026gt; boys, score= 0.67 \u0026gt; veela, score= 0.67 \u0026gt; attacks, score= 0.67  # Typo/OOV get_similar_words(\u0026quot;pormstrang\u0026quot;, 10)  word not in vocab \u0026gt; durmstrang, score= 0.96 \u0026gt; beauxbatons, score= 0.83 \u0026gt; ghosts, score= 0.81 \u0026gt; among, score= 0.75 \u0026gt; hufflepuffs, score= 0.74 \u0026gt; curses, score= 0.71 \u0026gt; effect, score= 0.71 \u0026gt; security, score= 0.70 \u0026gt; ghost, score= 0.70 \u0026gt; rules, score= 0.68  Looking at the results from Typos and OOV words, I think we are getting decent results for this to serve as a proof of concept.\nSub word embeddings are exemplified by https://fasttext.cc/ and more recently using Byte-Pair encodings https://github.com/bheinzerling/bpemb.\n"}).add({id:1,href:"/blog/nlp-series-part-2-word2vec-skipgram-negative-sampling/",title:"NLP Series [Part 2] · Word2Vec-SkipGram-Negative-Sampling",description:"Continuing with our previous post, we explore Word2Vec skip-gram model with negative sampling.",content:"Most of the steps are similar to our notebook on Word2Vec without negative sampling. The key changes happen with the dataset where we provide a list of indices for negative sample for each forward pass as well as the loss function.\nIn this notebook, we will train a Word2Vec skip-gram model with negative sampling from scratch on some text and inspect the trained embeddings at the end.\nThe first step for using any kind of NLP pipeline is to vectorize the text. Traditionally, we used to do this using one-hot representation of vectors. This had various downsides like:\n Vectors tend to be very long as their size depends on the vocabulary size of the corpus(which grows with the corpus size). They don\u0026rsquo;t have any understanding of the text. They are sparse and can\u0026rsquo;t be used for any comparison as any two one-hot encoded vector from a set will be orthogonal.  Word2vec is able to tackle all these challenges. The architecture we define later will enable us to learn a distributed representation for each word/token in our corpus. The key idea being, we can represent a word by adding contextual information to it. Context refers to the words/tokens neighbouring the word/token of interest to us.\nOf course this technique is not perfect and has it\u0026rsquo;s own downsides. The key downside being we loose the word/token ordering while training the word2vec model, hence we are essentially dealing with a bag of words model. This makes the resulting embeddings not suitable for sentence level representations. We will cover other techniques later (RNNs, Transformers) that produce embeddings more suitable for sentences. For now our sole focus will be learning good word/token level embeddings.\nFirst we will import the necessary libraries # from collections import Counter from random import sample import re from typing import List, Tuple import numpy as np import requests from sklearn.metrics.pairwise import cosine_similarity import torch import torch.nn as nn from torch.utils.data import DataLoader, Dataset  The whole process of training the embeddings can be broken down into the following key steps:\n We define a class TextProcessor that has methods to pre-process the text. fetch_text() fetches the texts directly from urls containing our text data. process_text() applies basic pre-procesing steps to the text and creates tokens using white space tokenization. prepare_vocab() creates token to index mapping and vice versa. Create torch Dataset and Dataloader where each index in the dataset will be a tuple, (center_word_ix, context_word_ix); i.e. pairs of indices of center word and context based on a pre defined window size.  The window side determines the number of context words around a center word. For example, window size of 5 will create the follwing center and context pairs for the sentence \u0026ldquo;a quick brown fox jumps\u0026rdquo; with \u0026ldquo;brown\u0026rdquo; being the center word - [(\u0026ldquo;brown\u0026rdquo;, \u0026ldquo;a\u0026rdquo;), (\u0026ldquo;brown\u0026rdquo;, \u0026ldquo;quick\u0026rdquo;), (\u0026ldquo;brown\u0026rdquo;, \u0026ldquo;fox\u0026rdquo;), (\u0026ldquo;brown\u0026rdquo;, \u0026ldquo;jumps\u0026rdquo;)]   Create our SkipGramModel model by defining a custom model on top of the torch.nn.Module. Define our loss function, optimizer and scheduler. Train the model for a certain number of epochs.  Finally, we will create a similarity matrix(cosine similarity) using the trained embeddings and explore similar embeddings for some word query.\nFetching and preparing the data # # We will be using the first four Harry Potter books. BASE_URL = \u0026quot;https://raw.githubusercontent.com/formcept/whiteboard/master/nbviewer/notebooks/data/harrypotter\u0026quot; BOOK_URLS = [ f\u0026quot;{BASE_URL}/Book%201%20-%20The%20Philosopher's%20Stone.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%202%20-%20The%20Chamber%20of%20Secrets.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%203%20-%20The%20Prisoner%20of%20Azkaban.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%204%20-%20The%20Goblet%20of%20Fire.txt\u0026quot; ]  class TextProcessor: def __init__(self, urls: List[str]): self.urls = urls def fetch_text(self): self.text = \u0026quot;\u0026quot; for i, url in enumerate(self.urls): r = requests.get(url) self.text += \u0026quot;\\n\\n\\n\u0026quot; + r.text print(f\u0026quot;Fetched {i+1}/{len(self.urls)} urls ...\u0026quot;) def process_text(self): print(\u0026quot;Processing text ...\u0026quot;) sentences = re.split(\u0026quot;\\n{2,}\u0026quot;, self.text) print(f\u0026quot;{len(sentences)} sentences\u0026quot;) self.clean_sentences = [] for txt in sentences: txt = txt.strip().lower() txt = txt.replace(\u0026quot;\\n\u0026quot;, \u0026quot;\u0026quot;) txt = \u0026quot; \u0026quot;.join(re.findall(\u0026quot;\\w+\u0026quot;, txt)) if txt: self.clean_sentences.append(txt) # Tokens and token counter will be used later to create a vocabulary for # us which will be used to map words/tokens to indices and vice versa, to # create training data and recreate the texts from predictions respectively. print(f\u0026quot;{len(sentences)} filtered sentences\u0026quot;) tokens = \u0026quot; \u0026quot;.join(self.clean_sentences).split(\u0026quot; \u0026quot;) print(f\u0026quot;{len(tokens)} tokens\u0026quot;) self.token_counter = Counter(tokens) print(f\u0026quot;{len(self.token_counter)} unique tokens\u0026quot;) def prepare_vocab(self, min_count: int): # min_count is the minimum number of times a token should appear in the # text to be considered in the vocabulary else they are assigned to a # default index which is equal to `len(vocab)`. self.w2ix = {} for i, (token, count) in enumerate( self.token_counter.most_common(len(self.token_counter)) ): if count \u0026lt; min_count: break else: self.w2ix[token] = i self.ix2w = {ix: w for w, ix in self.w2ix.items()} # Assign default index to rest of the tokens n = len(self.w2ix) for token, _ in self.token_counter.most_common(len(self.token_counter)): if token not in self.w2ix: self.w2ix[token] = n self.ix2w[n] = \u0026quot;\u0026lt;unk\u0026gt;\u0026quot; self.ixs = list(self.ix2w.keys()) self.vocab_size = n + 1 print(f\u0026quot;Vocab size: {self.vocab_size}\u0026quot;)  text_processor = TextProcessor(BOOK_URLS)  text_processor.fetch_text() # Fetched 1/4 urls ... # Fetched 2/4 urls ... # Fetched 3/4 urls ... # Fetched 4/4 urls ...  text_processor.process_text() # Processing text ... # 20033 sentences # 20033 filtered sentences # 501854 tokens # 15078 unique tokens  text_processor.prepare_vocab(min_count=20) # Vocab size: 2103  Preparing the torch Dataset and Dataloader # The Dataloader will enable us to send data in batches during the forward pass of the model training.\nN_NEG_SAMPLES = 20  class HarryPotterDataset(Dataset): def __init__(self, text_processor: TextProcessor, window_size: int=3): self.data = [] for txt in text_processor.clean_sentences: splits = txt.split(\u0026quot; \u0026quot;) for i in range(window_size, len(splits) -1): center_word = splits[i] window_words = splits[i-window_size:i]+splits[i+1:i+window_size+1] for context in window_words: # Each data point under self.data will be a tuple with index 0 # containing the index(w2ix) for center_word and # index 1 containing the index(w2ix) for context_word and # index 2 containing negative samples self.data.append(( text_processor.w2ix[center_word], text_processor.w2ix[context], sample(text_processor.ixs, N_NEG_SAMPLES) )) def __getitem__(self, ix: int): return self.data[ix] def __len__(self): return len(self.data)  The Dataset essentially contains indexes of pairs of center word and a context word.\ndataset = HarryPotterDataset(text_processor, 3) len(dataset) # 2489461  def collate_fn(collate_fn_input: List[Tuple]): return ( torch.LongTensor([i[0] for i in collate_fn_input]), # center word torch.LongTensor([i[1] for i in collate_fn_input]), # context word torch.LongTensor([i[2] for i in collate_fn_input]) # negative samples )  dataloader = DataLoader(dataset, batch_size=64, collate_fn=collate_fn, shuffle=True)  Creating the Word2Vec model using torch.nn.Module # class SkipGramModel(nn.Module): def __init__(self, vocab_size: int, embedding_size: int=50): super().__init__() self.u_embeddings = nn.Embedding(vocab_size, embedding_size) self.v_embeddings = nn.Embedding(vocab_size, embedding_size) def forward(self, pos_u, pos_v, neg_v): losses = [] emb_u = self.u_embeddings(pos_u) emb_v = self.v_embeddings(pos_v) score = torch.mul(emb_u, emb_v).squeeze() score = torch.sum(score, dim=1) score = nn.functional.logsigmoid(score) losses.append(sum(score)) neg_emb_v = self.v_embeddings(neg_v) neg_score = torch.bmm(neg_emb_v, emb_u.unsqueeze(2)).squeeze() neg_score = torch.sum(neg_score, dim=1) neg_score = nn.functional.logsigmoid(-1 * neg_score) losses.append(sum(neg_score)) return -1 * sum(losses)  Embedding is nothing but \u0026ldquo;A simple lookup table that stores embeddings of a fixed dictionary and size\u0026rdquo; - pytorch documentation.\nThe modified loss function for negative sampling is:\n  Source: https://lena-voita.github.io/nlp_course/word_embeddings.html\nIn each forward pass we:\n Pass indices of center word as input param pos_u. These indices are looked up in the self.u_embeddings table. pos_v is the index for context word and self.v_embeddings is the associated embedding table. score is the first part of the loss function, i.e. the component we need to increase(similarity between the center and context vectors) neg_score is the second part of the loss function, i.e. the component we need to decrease(similarity between the center embedding and negative embeddings)  A trained model should output high values for the context indices for a given center word.\ndevice = torch.device(\u0026quot;cuda\u0026quot; if torch.cuda.is_available() else \u0026quot;cpu\u0026quot;) model = SkipGramModel(text_processor.vocab_size, embedding_size=30).to(device)  Defining our loss function, optimizer and scheduler # optimizer = torch.optim.Adam(model.parameters(), lr=0.005) scheduler = torch.optim.lr_scheduler.StepLR(optimizer, step_size=8, gamma=0.5)  N_EPOCHS = 10 STEP_TO_LOG = 10000  Training the model # epoch_losses = [] batch_losses = [] for epoch in range(N_EPOCHS): losses = [] for i, data in enumerate(dataloader): inputs = data[0].to(device) outputs = data[1].to(device) neg_samples = data[2].to(device) loss = model(inputs, outputs, neg_samples) losses.append(loss.item()) loss.backward() optimizer.step() optimizer.zero_grad() if i % STEP_TO_LOG == 0: print(f\u0026quot;epoch {epoch + 1}; steps={i:\u0026gt;5}/{len(dataloader)}; loss={loss:\u0026lt;.5f}\u0026quot;) scheduler.step() batch_losses += losses epoch_losses.append(np.mean(losses)) print(f\u0026quot;epoch {epoch + 1} ; lr={scheduler._last_lr[0]}; loss={epoch_losses[-1]:\u0026lt;.5f}\\n\u0026quot;)  epoch 1; steps= 0/38898; loss=546.31952 epoch 1; steps=10000/38898; loss=35.40395 epoch 1; steps=20000/38898; loss=32.84525 epoch 1; steps=30000/38898; loss=16.26216 epoch 1 ; lr=0.005; loss=41.96464 epoch 2; steps= 0/38898; loss=22.99003 epoch 2; steps=10000/38898; loss=9.72049 epoch 2; steps=20000/38898; loss=10.83452 epoch 2; steps=30000/38898; loss=18.22450 epoch 2 ; lr=0.005; loss=21.12818 epoch 3; steps= 0/38898; loss=25.02730 epoch 3; steps=10000/38898; loss=18.92863 epoch 3; steps=20000/38898; loss=21.43628 epoch 3; steps=30000/38898; loss=11.29200 epoch 3 ; lr=0.005; loss=20.39987 epoch 4; steps= 0/38898; loss=13.29572 epoch 4; steps=10000/38898; loss=15.42674 epoch 4; steps=20000/38898; loss=29.97781 epoch 4; steps=30000/38898; loss=24.73233 epoch 4 ; lr=0.005; loss=20.14466 epoch 5; steps= 0/38898; loss=22.58458 epoch 5; steps=10000/38898; loss=14.22814 epoch 5; steps=20000/38898; loss=29.62961 epoch 5; steps=30000/38898; loss=29.37720 epoch 5 ; lr=0.005; loss=19.99422 epoch 6; steps= 0/38898; loss=11.45635 epoch 6; steps=10000/38898; loss=7.82920 epoch 6; steps=20000/38898; loss=21.33622 epoch 6; steps=30000/38898; loss=15.23507 epoch 6 ; lr=0.005; loss=19.93158 epoch 7; steps= 0/38898; loss=20.86297 epoch 7; steps=10000/38898; loss=20.90056 epoch 7; steps=20000/38898; loss=12.09392 epoch 7; steps=30000/38898; loss=21.14314 epoch 7 ; lr=0.005; loss=19.85268 epoch 8; steps= 0/38898; loss=21.31746 epoch 8; steps=10000/38898; loss=17.20284 epoch 8; steps=20000/38898; loss=14.42716 epoch 8; steps=30000/38898; loss=14.52877 epoch 8 ; lr=0.0025; loss=19.86401 epoch 9; steps= 0/38898; loss=14.28189 epoch 9; steps=10000/38898; loss=12.93937 epoch 9; steps=20000/38898; loss=10.24370 epoch 9; steps=30000/38898; loss=7.36204 epoch 9 ; lr=0.0025; loss=17.23494 epoch 10; steps= 0/38898; loss=16.67952 epoch 10; steps=10000/38898; loss=15.78232 epoch 10; steps=20000/38898; loss=11.98835 epoch 10; steps=30000/38898; loss=11.23106 epoch 10 ; lr=0.0025; loss=16.56899  weights = model.u_embeddings.weight.detach().cpu().numpy() weights.shape # (2103, 30)  Creating the similarity matrix # similarity = cosine_similarity(weights, weights)  def get_similar_words(input_word: str, n: int): if input_word not in text_processor.w2ix: print(\u0026quot;word not in vocab\u0026quot;) else: input_word_ix = text_processor.w2ix[input_word] similarity_vector = similarity[input_word_ix] most_similar_ixs = np.argsort(similarity_vector)[-n:][::-1] most_similar_words = [(text_processor.ix2w[ix], similarity_vector[ix]) for ix in most_similar_ixs] for word, score in most_similar_words: print(f\u0026quot; \u0026gt; {word}, score={score: .2f}\u0026quot;)  Exploring similar embeddings for some queries \u0026hellip;\nget_similar_words(\u0026quot;snape\u0026quot;, 10)   \u0026gt; snape, score= 1.00 \u0026gt; moody, score= 0.60 \u0026gt; dumbledore, score= 0.59 \u0026gt; everyone, score= 0.58 \u0026gt; harry, score= 0.56 \u0026gt; lupin, score= 0.55 \u0026gt; added, score= 0.53 \u0026gt; skeeter, score= 0.53 \u0026gt; thoughts, score= 0.52 \u0026gt; moment, score= 0.52  get_similar_words(\u0026quot;vernon\u0026quot;, 10)   \u0026gt; vernon, score= 1.00 \u0026gt; uncle, score= 0.93 \u0026gt; aunt, score= 0.78 \u0026gt; petunia, score= 0.74 \u0026gt; marge, score= 0.69 \u0026gt; she, score= 0.63 \u0026gt; neville, score= 0.63 \u0026gt; asleep, score= 0.62 \u0026gt; cry, score= 0.61 \u0026gt; dudley, score= 0.59  get_similar_words(\u0026quot;muggle\u0026quot;, 10)   \u0026gt; muggle, score= 1.00 \u0026gt; love, score= 0.77 \u0026gt; hasn, score= 0.69 \u0026gt; mentioned, score= 0.68 \u0026gt; famous, score= 0.65 \u0026gt; care, score= 0.65 \u0026gt; name, score= 0.65 \u0026gt; wanted, score= 0.63 \u0026gt; arts, score= 0.63 \u0026gt; born, score= 0.63  get_similar_words(\u0026quot;harry\u0026quot;, 10)   \u0026gt; harry, score= 1.00 \u0026gt; him, score= 0.77 \u0026gt; ron, score= 0.75 \u0026gt; he, score= 0.73 \u0026gt; then, score= 0.71 \u0026gt; hermione, score= 0.70 \u0026gt; she, score= 0.67 \u0026gt; as, score= 0.61 \u0026gt; but, score= 0.61 \u0026gt; moody, score= 0.61  get_similar_words(\u0026quot;buckbeak\u0026quot;, 10)   \u0026gt; buckbeak, score= 1.00 \u0026gt; furiously, score= 0.59 \u0026gt; cabinet, score= 0.55 \u0026gt; beak, score= 0.54 \u0026gt; hippogriff, score= 0.54 \u0026gt; muttered, score= 0.51 \u0026gt; crookshanks, score= 0.51 \u0026gt; lying, score= 0.50 \u0026gt; bag, score= 0.49 \u0026gt; eye, score= 0.48  get_similar_words(\u0026quot;slytherin\u0026quot;, 10)   \u0026gt; slytherin, score= 1.00 \u0026gt; krum, score= 0.65 \u0026gt; seeker, score= 0.63 \u0026gt; team, score= 0.61 \u0026gt; eaters, score= 0.60 \u0026gt; shrieked, score= 0.60 \u0026gt; alicia, score= 0.58 \u0026gt; chasers, score= 0.58 \u0026gt; months, score= 0.58 \u0026gt; death, score= 0.57  get_similar_words(\u0026quot;malfoy\u0026quot;, 10)   \u0026gt; malfoy, score= 1.00 \u0026gt; cedric, score= 0.58 \u0026gt; without, score= 0.58 \u0026gt; harry, score= 0.52 \u0026gt; added, score= 0.52 \u0026gt; head, score= 0.51 \u0026gt; just, score= 0.50 \u0026gt; away, score= 0.49 \u0026gt; something, score= 0.49 \u0026gt; draco, score= 0.48  There are various Intrisic and Extrinsic evaluation criterias for these embeddings. For Evaluation and Interpretation of the embeddings, take a look here - https://lena-voita.github.io/nlp_course/word_embeddings.html#evaluation.\nHere, the model convergance was not as good as our previous training without negative sampling and some of the similarity results on manual inspection look a little off. There could be a problem with our model or the amount of training we did. We did not exactly follow the steps mentioned in the original paper to be honest.\nStill, I just wanted to cover this for the sake of completeness. Up next, we will move onto sub word embedding techniques which would allow us to handle out of vocab tokens/words.\n"}).add({id:2,href:"/blog/nlp-series-part-1-word2vec-skipgram/",title:"NLP Series [Part 1] · Word2Vec-SkipGram",description:"We will take a walk down the memory lane and visit the awesome Word2Vec.",content:"In this notebook, we will train a Word2Vec skip-gram model from scratch on some text and inspect the trained embeddings at the end.\nThe first step for using any kind of NLP pipeline is to vectorize the text. Traditionally, we used to do this using one-hot representation of vectors. This had various downsides like:\n Vectors tend to be very long as their size depends on the vocabulary size of the corpus(which grows with the corpus size). They don\u0026rsquo;t have any understanding of the text. They are sparse and can\u0026rsquo;t be used for any comparison as any two one-hot encoded vector from a set will be orthogonal.  Word2vec is able to tackle all these challenges. The architecture we define later will enable us to learn a distributed representation for each word/token in our corpus. The key idea being, we can represent a word by adding contextual information to it. Context refers to the words/tokens neighbouring the word/token of interest to us.\nOf course this technique is not perfect and has it\u0026rsquo;s own downsides. The key downside being we loose the word/token ordering while training the word2vec model, hence we are essentially dealing with a bag of words model. This makes the resulting embeddings not suitable for sentence level representations. We will cover other techniques later (RNNs, Transformers) that produce embeddings more suitable for sentences. For now our sole focus will be learning good word/token level embeddings.\nFirst we will import the necessary libraries # from collections import Counter import re from typing import List import numpy as np import requests from sklearn.metrics.pairwise import cosine_similarity import torch import torch.nn as nn from torch.utils.data import DataLoader, Dataset  The whole process of training the embeddings can be broken down into the following key steps:\n We define a class TextProcessor that has methods to pre-process the text. `fetch_text() fetches the texts directly from urls containing our text data. process_text() applies basic pre-procesing steps to the text and creates tokens using white space tokenization. prepare_vocab() creates token to index mapping and vice versa. Create torch Dataset and Dataloader where each index in the dataset will be a tuple, (center_word_ix, context_word_ix); i.e. pairs of indices of center word and context based on a pre defined window size.  The window side determines the number of context words around a center word. For example, window size of 5 will create the follwing center and context pairs for the sentence \u0026ldquo;a quick brown fox jumps\u0026rdquo; with \u0026ldquo;brown\u0026rdquo; being the center word - [(\u0026ldquo;brown\u0026rdquo;, \u0026ldquo;a\u0026rdquo;), (\u0026ldquo;brown\u0026rdquo;, \u0026ldquo;quick\u0026rdquo;), (\u0026ldquo;brown\u0026rdquo;, \u0026ldquo;fox\u0026rdquo;), (\u0026ldquo;brown\u0026rdquo;, \u0026ldquo;jumps\u0026rdquo;)]   Create our SkipGramModel model by defining a custom model on top of the torch.nn.Module. Define our loss function, optimizer and scheduler. Train the model for a certain number of epochs.  Finally, we will create a similarity matrix(cosine similarity) using the trained embeddings and explore similar embeddings for some word query.\nFetching and preparing the data # # We will be using the first four Harry Potter books. BASE_URL = \u0026quot;https://raw.githubusercontent.com/formcept/whiteboard/master/nbviewer/notebooks/data/harrypotter\u0026quot; BOOK_URLS = [ f\u0026quot;{BASE_URL}/Book%201%20-%20The%20Philosopher's%20Stone.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%202%20-%20The%20Chamber%20of%20Secrets.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%203%20-%20The%20Prisoner%20of%20Azkaban.txt\u0026quot;, f\u0026quot;{BASE_URL}/Book%204%20-%20The%20Goblet%20of%20Fire.txt\u0026quot; ]  class TextProcessor: def __init__(self, urls: List[str]): self.urls = urls def fetch_text(self): self.text = \u0026quot;\u0026quot; for i, url in enumerate(self.urls): r = requests.get(url) self.text += \u0026quot;\\n\\n\\n\u0026quot; + r.text print(f\u0026quot;Fetched {i+1}/{len(self.urls)} urls ...\u0026quot;) def process_text(self): print(\u0026quot;Processing text ...\u0026quot;) sentences = re.split(\u0026quot;\\n{2,}\u0026quot;, self.text) print(f\u0026quot;{len(sentences)} sentences\u0026quot;) self.clean_sentences = [] for txt in sentences: txt = txt.strip().lower() txt = txt.replace(\u0026quot;\\n\u0026quot;, \u0026quot;\u0026quot;) txt = \u0026quot; \u0026quot;.join(re.findall(\u0026quot;\\w+\u0026quot;, txt)) if txt: self.clean_sentences.append(txt) # Tokens and token counter will be used later to create a vocabulary for # us which will be used to map words/tokens to indices and vice versa, to # create training data and recreate the texts from predictions respectively. print(f\u0026quot;{len(sentences)} filtered sentences\u0026quot;) tokens = \u0026quot; \u0026quot;.join(self.clean_sentences).split(\u0026quot; \u0026quot;) print(f\u0026quot;{len(tokens)} tokens\u0026quot;) self.token_counter = Counter(tokens) print(f\u0026quot;{len(self.token_counter)} unique tokens\u0026quot;) def prepare_vocab(self, min_count: int): # min_count is the minimum number of times a token should appear in the # text to be considered in the vocabulary else they are assigned to a # default index which is equal to `len(vocab)`. self.w2ix = {} for i, (token, count) in enumerate( self.token_counter.most_common(len(self.token_counter)) ): if count \u0026lt; min_count: break else: self.w2ix[token] = i self.ix2w = {ix: w for w, ix in self.w2ix.items()} # Assign default index to rest of the tokens n = len(self.w2ix) for token, _ in self.token_counter.most_common(len(self.token_counter)): if token not in self.w2ix: self.w2ix[token] = n self.ix2w[n] = \u0026quot;\u0026lt;unk\u0026gt;\u0026quot; self.vocab_size = n + 1 print(f\u0026quot;Vocab size: {self.vocab_size}\u0026quot;)  text_processor = TextProcessor(BOOK_URLS)  text_processor.fetch_text() # Fetched 1/4 urls ... # Fetched 2/4 urls ... # Fetched 3/4 urls ... # Fetched 4/4 urls ...  text_processor.process_text() # Processing text ... # 20033 sentences # 20033 filtered sentences # 501854 tokens # 15078 unique tokens  text_processor.prepare_vocab(min_count=20) # Vocab size: 2103  Preparing the torch Dataset and Dataloader # The Dataloader will enable us to send data in batches during the forward pass of the model training.\nclass HarryPotterDataset(Dataset): def __init__(self, text_processor: TextProcessor, window_size: int=3): self.data = [] for txt in text_processor.clean_sentences: splits = txt.split(\u0026quot; \u0026quot;) for i in range(window_size, len(splits) -1): center_word = splits[i] window_words = splits[i-window_size:i]+splits[i+1:i+window_size+1] for context in window_words: # Each data point under self.data will be a tuple with index 0 # containing the index(w2ix) for center_word and # index 1 containing the index(w2ix) for context_word self.data.append((text_processor.w2ix[center_word], text_processor.w2ix[context])) def __getitem__(self, ix: int): return self.data[ix] def __len__(self): return len(self.data)  dataset = HarryPotterDataset(text_processor, 3) len(dataset) # 2489461  dataloader = DataLoader(dataset, batch_size=64, shuffle=True)  Creating the Word2Vec model using torch.nn.Module # class SkipGramModel(nn.Module): def __init__(self, vocab_size: int, embedding_size: int=50): super().__init__() self.embedding = nn.Embedding(vocab_size, embedding_size) self.linear = nn.Linear(embedding_size, vocab_size) def forward(self, x): return self.linear(self.embedding(x))  The model architecure is Embedding -\u0026gt; Linear -\u0026gt; Softmax.\nEmbedding is nothing but \u0026ldquo;A simple lookup table that stores embeddings of a fixed dictionary and size\u0026rdquo; - pytorch documentation.\nBased on our model architecture, this layer will contain the trained token/word embeddings of interest to us and we will discard the weight matrix from the Linear layer.\nIn each forward pass we:\n Pass indices of center word as input x. These indices are looked up in the self.embedding table. We transform the vector from last step using the Linear layer to get another vector with dimension vocab_size. Finally we apply softmax and calcualte loss.  A trained model should output high values for the context indices for a given center word.\ndevice = torch.device(\u0026quot;cuda\u0026quot; if torch.cuda.is_available() else \u0026quot;cpu\u0026quot;) model = SkipGramModel(text_processor.vocab_size, embedding_size=30).to(device)  Defining our loss function, optimizer and scheduler # criterion = nn.CrossEntropyLoss() optimizer = torch.optim.Adam(model.parameters(), lr=0.005) scheduler = torch.optim.lr_scheduler.StepLR(optimizer, step_size=5, gamma=0.5)  N_EPOCHS = 10 STEP_TO_LOG = 10000  Training the model # epoch_losses = [] batch_losses = [] for epoch in range(N_EPOCHS): losses = [] for i, data in enumerate(dataloader): inputs = data[0].long().to(device) outputs = data[1].long().to(device) pred = model(inputs) loss = criterion(pred, outputs) losses.append(loss.item()) loss.backward() optimizer.step() optimizer.zero_grad() if i % STEP_TO_LOG == 0: print(f\u0026quot;epoch {epoch + 1}; steps={i:\u0026gt;5}/{len(dataloader)}; loss={loss:\u0026lt;.5f}\u0026quot;) scheduler.step() batch_losses += losses epoch_losses.append(np.mean(losses)) print(f\u0026quot;epoch {epoch + 1} ; lr={scheduler._last_lr[0]}; loss={epoch_losses[-1]:\u0026lt;.5f}\\n\u0026quot;)  epoch 1; steps= 0/38898; loss=7.80020 epoch 1; steps=10000/38898; loss=5.55375 epoch 1; steps=20000/38898; loss=5.58139 epoch 1; steps=30000/38898; loss=5.27452 epoch 1 ; lr=0.005; loss=5.60440 epoch 2; steps= 0/38898; loss=4.85012 epoch 2; steps=10000/38898; loss=5.81531 epoch 2; steps=20000/38898; loss=5.07261 epoch 2; steps=30000/38898; loss=5.62864 epoch 2 ; lr=0.005; loss=5.52841 epoch 3; steps= 0/38898; loss=5.27015 epoch 3; steps=10000/38898; loss=5.55336 epoch 3; steps=20000/38898; loss=5.67527 epoch 3; steps=30000/38898; loss=5.60372 epoch 3 ; lr=0.005; loss=5.52233 epoch 4; steps= 0/38898; loss=5.50681 epoch 4; steps=10000/38898; loss=5.48357 epoch 4; steps=20000/38898; loss=5.18897 epoch 4; steps=30000/38898; loss=5.74382 epoch 4 ; lr=0.005; loss=5.52111 epoch 5; steps= 0/38898; loss=5.67365 epoch 5; steps=10000/38898; loss=5.66463 epoch 5; steps=20000/38898; loss=5.82155 epoch 5; steps=30000/38898; loss=5.77744 epoch 5 ; lr=0.0025; loss=5.52081 epoch 6; steps= 0/38898; loss=5.54513 epoch 6; steps=10000/38898; loss=5.40478 epoch 6; steps=20000/38898; loss=5.71839 epoch 6; steps=30000/38898; loss=5.23344 epoch 6 ; lr=0.0025; loss=5.47719 epoch 7; steps= 0/38898; loss=4.93150 epoch 7; steps=10000/38898; loss=5.09374 epoch 7; steps=20000/38898; loss=5.47905 epoch 7; steps=30000/38898; loss=5.92455 epoch 7 ; lr=0.0025; loss=5.47128 epoch 8; steps= 0/38898; loss=5.22414 epoch 8; steps=10000/38898; loss=5.67435 epoch 8; steps=20000/38898; loss=5.55853 epoch 8; steps=30000/38898; loss=5.28791 epoch 8 ; lr=0.0025; loss=5.47099 epoch 9; steps= 0/38898; loss=5.33284 epoch 9; steps=10000/38898; loss=5.80998 epoch 9; steps=20000/38898; loss=6.04806 epoch 9; steps=30000/38898; loss=5.58979 epoch 9 ; lr=0.0025; loss=5.47106 epoch 10; steps= 0/38898; loss=5.09184 epoch 10; steps=10000/38898; loss=5.18391 epoch 10; steps=20000/38898; loss=5.66316 epoch 10; steps=30000/38898; loss=5.44824 epoch 10 ; lr=0.00125; loss=5.47111  weights = model.embedding.weight.detach().cpu().numpy() weights.shape # (2103, 30)  Creating the similarity matrix # similarity = cosine_similarity(weights, weights)  def get_similar_words(input_word: str, n: int): if input_word not in text_processor.w2ix: print(\u0026quot;word not in vocab\u0026quot;) else: input_word_ix = text_processor.w2ix[input_word] similarity_vector = similarity[input_word_ix] most_similar_ixs = np.argsort(similarity_vector)[-n:][::-1] most_similar_words = [(text_processor.ix2w[ix], similarity_vector[ix]) for ix in most_similar_ixs] for word, score in most_similar_words: print(f\u0026quot; \u0026gt; {word}, score={score: .2f}\u0026quot;)  Exploring similar embeddings for some queries \u0026hellip; # get_similar_words(\u0026quot;snape\u0026quot;, 10)   \u0026gt; snape, score= 1.00 \u0026gt; karkaroff, score= 0.81 \u0026gt; dumbledore, score= 0.79 \u0026gt; lupin, score= 0.77 \u0026gt; mcgonagall, score= 0.76 \u0026gt; moody, score= 0.74 \u0026gt; professor, score= 0.72 \u0026gt; flitwick, score= 0.71 \u0026gt; trelawney, score= 0.69 \u0026gt; quirrell, score= 0.69  get_similar_words(\u0026quot;vernon\u0026quot;, 10)   \u0026gt; vernon, score= 1.00 \u0026gt; aunt, score= 0.81 \u0026gt; uncle, score= 0.79 \u0026gt; dudley, score= 0.78 \u0026gt; petunia, score= 0.70 \u0026gt; marge, score= 0.62 \u0026gt; furious, score= 0.59 \u0026gt; telephone, score= 0.53 \u0026gt; sister, score= 0.53 \u0026gt; company, score= 0.52  get_similar_words(\u0026quot;muggle\u0026quot;, 10)   \u0026gt; muggle, score= 1.00 \u0026gt; wizarding, score= 0.81 \u0026gt; old, score= 0.65 \u0026gt; yer, score= 0.63 \u0026gt; international, score= 0.61 \u0026gt; important, score= 0.61 \u0026gt; our, score= 0.61 \u0026gt; is, score= 0.61 \u0026gt; young, score= 0.60 \u0026gt; yourself, score= 0.60  get_similar_words(\u0026quot;harry\u0026quot;, 10)   \u0026gt; harry, score= 1.00 \u0026gt; lupin, score= 0.64 \u0026gt; ron, score= 0.63 \u0026gt; hermione, score= 0.61 \u0026gt; she, score= 0.57 \u0026gt; he, score= 0.57 \u0026gt; colin, score= 0.54 \u0026gt; dumbledore, score= 0.52 \u0026gt; furiously, score= 0.51 \u0026gt; moody, score= 0.49  get_similar_words(\u0026quot;slytherin\u0026quot;, 10)   \u0026gt; slytherin, score= 1.00 \u0026gt; gryffindor, score= 0.79 \u0026gt; hufflepuff, score= 0.75 \u0026gt; team, score= 0.71 \u0026gt; heir, score= 0.71 \u0026gt; ravenclaw, score= 0.66 \u0026gt; goal, score= 0.64 \u0026gt; seeker, score= 0.64 \u0026gt; wood, score= 0.60 \u0026gt; irish, score= 0.60  get_similar_words(\u0026quot;malfoy\u0026quot;, 10)   \u0026gt; malfoy, score= 1.00 \u0026gt; goyle, score= 0.77 \u0026gt; crabbe, score= 0.64 \u0026gt; draco, score= 0.61 \u0026gt; diggory, score= 0.59 \u0026gt; lucius, score= 0.57 \u0026gt; weasley, score= 0.51 \u0026gt; laughing, score= 0.50 \u0026gt; pettigrew, score= 0.50 \u0026gt; percy, score= 0.50  There are various Intrisic and Extrinsic evaluation criterias for these embeddings. For Evaluation and Interpretation of the embeddings take a look here - https://lena-voita.github.io/nlp_course/word_embeddings.html#evaluation.\nIn the next notebook, we will modify our loss function to support negative sampling to improve the training speed.\n"}).add({id:3,href:"/blog/mlops-template-part-4-fastapi-elasticapm/",title:"MLOps template [Part 4] · FastAPI + ElasticAPM",description:"We will use FastAPI to serve our trained models behind a REST endpoint.",content:"Scripts related to the APIs are located at MLOps/app.\n├── application.py # FastAPI app and launcher uvicorn.run ├── models # pydantic model for reponse validation │ └── predict.py # pydantic model for predict endpoint └── routes # to maintain larger applications ├── endpoints │ └── predict.py # predict endpoint └── router.py # APIRouter module to maintain larger apps  Though we have used the APIRouter module here, it\u0026rsquo;s really needed when we have lots of API endpoints in a larger app.\nLook at https://fastapi.tiangolo.com/tutorial/bigger-applications/\nModel Artifacts # To use the model to get predictions, we need to load all the model related artifacts.\nWe load the trained model directly using the mlflow.sklearn module. Here we load the version number 1 of our sk-learn-naive-bayes-clf-model model.\n# manually pick the model version from trained models sk_model = mlflow.sklearn.load_model(model_uri=\u0026quot;models:/sk-learn-naive-bayes-clf-model/1\u0026quot;) # mlflow does not store data manipulation routines like label encoding # we need to manage the LabelEncoder and TfidfVectorizer ourselves with open(BASE_DIR / \u0026quot;artifacts/target_encoder.pkl\u0026quot;, \u0026quot;rb\u0026quot;) as f: target_encoder = pickle.load(f) with open(BASE_DIR / \u0026quot;artifacts/vectorizer.pkl\u0026quot;, \u0026quot;rb\u0026quot;) as f: vectorizer = pickle.load(f) logger.info(\u0026quot;Loaded model artifacts\u0026quot;)  Beyond the trained classifier, we also need the TfidfVectorizer to vectorize the text and LabelEncoder to map the predictions to actual labels.\nThese artifacts are not saved/managed by MLflow as it only mangages the artifacts realted to the ML algorithm. #\n Exclude certain preprocessing \u0026amp; feature manipulation estimators from patching. These estimators represent data manipulation routines (e.g., normalization, label encoding) rather than ML algorithms. Accordingly, we should not create MLflow runs and log parameters / metrics for these routines, unless they are captured as part of an ML pipeline (via sklearn.pipeline.Pipeline)\n # manually pick the model version from trained models sk_model = mlflow.sklearn.load_model(model_uri=\u0026quot;models:/sk-learn-naive-bayes-clf-model/1\u0026quot;) # mlflow does not store data manipulation routines like label encoding # we need to manage the TfidfVectorizer and TfidfVectorizer ourselves with open(BASE_DIR / \u0026quot;artifacts/target_encoder.pkl\u0026quot;, \u0026quot;rb\u0026quot;) as f: target_encoder = pickle.load(f) with open(BASE_DIR / \u0026quot;artifacts/vectorizer.pkl\u0026quot;, \u0026quot;rb\u0026quot;) as f: vectorizer = pickle.load(f) logger.info(\u0026quot;Loaded model artifacts\u0026quot;)  Predict Endpoint # # Let\u0026rsquo;s look at the /predict endpoint.\n@router.post(\u0026quot;/predict\u0026quot;) async def predit(text: str) -\u0026gt; PredictResponseModel: logger.info(f\u0026quot;Received text for prediction: {text}\u0026quot;) processed_text_list = preprocess_text([text]) x = vectorizer.transform(processed_text_list) pred = sk_model.predict_proba(x) mapped_pred = dict(zip(target_encoder.classes_, pred[0])) logger.info(f\u0026quot;Prediction: {mapped_pred}\u0026quot;) return PredictResponseModel(preds=mapped_pred).preds  Here, we preprocess the text using preprocess_text(), vectorize it using vectorizer.transform() and finally generate predictions using the classifier sk_model.predict_proba().\nWe then map the probabilities to the actual labels(target_encoder.classes_) and return the predictions by wrapping around the PredictResponseModel pydantic model for data validation.\nThe API can be accessed at http://127.0.0.1:8010/docs.\n  ElasticAPM # We have also added ElasticAPM as a middleware for monitoring our FastAPI application. #\nimport uvicorn from elasticapm.contrib.starlette import ElasticAPM, make_apm_client from fastapi import FastAPI from loguru import logger from mlops.app.routes.router import api_router def get_fastapi_application() -\u0026gt; FastAPI: application = FastAPI(title=\u0026quot;MLOps\u0026quot;) application.add_middleware( ElasticAPM, client=make_apm_client({\u0026quot;SERVICE_NAME\u0026quot;: \u0026quot;MLOps Example\u0026quot;}) ) application.include_router(api_router) return application app = get_fastapi_application() if __name__ == \u0026quot;__main__\u0026quot;: logger.info(\u0026quot;*** Starting Prediction Server ***\u0026quot;) uvicorn.run(app, host=\u0026quot;127.0.0.1\u0026quot;, port=8010)  Once we start using the /predict endpoint, we can head over to http://localhost:5601/ to look at the app related metrics like Latency, Throughput etc, and system level metrics like CPU usage and System memory usage.\n    Under the hood, it uses Elastic Search, Kibana and an APM server launched using the docker-compose-monitoring.yaml during the setup.\nThe dashboard also provides a trace for each request.\n"}).add({id:4,href:"/blog/mlops-template-part-3-mlflow-minio/",title:"MLOps template [Part 3] · MLflow + MinIO",description:"In the last part, we saw our pipeline at the end. Steps 1-5 deal with data manipulation. We train our model in step 6 and that's where `MLflow` comes into picture.",content:"@pipeline def ml_pipeline(): # 1. fetch training data texts, target = get_training_dataset() # 2. minimal text preprocessing # 3. tfidf vectorization vectorizer, X = get_vectorizer_and_features(preprocess_text(texts)) # 4. target encoding target_encoder, encoded_target = get_targetencoder_and_encoded_targets(target) # 5. train test split X_train, X_test, y_train, y_test = train_test_split(X, encoded_target) # 6. model training, validation, registry, artifact storage train_clf(X_train, X_test, y_train, y_test)  MLflow # #  MLflow is an open source platform for managing the end-to-end machine learning lifecycle. It tackles four primary functions:\nTracking experiments to record and compare parameters and results (MLflow Tracking).\nPackaging ML code in a reusable, reproducible form in order to share with other data scientists or transfer to production (MLflow Projects).\nManaging and deploying models from a variety of ML libraries to a variety of model serving and inference platforms (MLflow Models).\nProviding a central model store to collaboratively manage the full lifecycle of an MLflow Model, including model versioning, stage transitions, and annotations (MLflow Model Registry).\n For our usecase, we mainly focus on Mlflow Tracking and Mlflow Registry. train_clf() internally calls train_and_validate_clf() located at mlops/ml_workflow/naive_bayes_clf.py.\nThis script has as all the MLflow components and we will look at those in detail.\nTracking # # # setting env vars for minio artifact storage set_env_vars() mlflow.set_tracking_uri(os.getenv(\u0026quot;MLFLOW_TRACKING_URI\u0026quot;)) # creates a new mlflow experiment MLFLOW_EXPERIMENT_NAME if it doesn't exist exps = [exp.name for exp in mlflow.tracking.MlflowClient().list_experiments()] if not os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;) in exps: mlflow.create_experiment( os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;), artifact_location=os.getenv(\u0026quot;MLFLOW_ARTIFACT_LOCATION\u0026quot;), )   MLflow runs can be recorded to local files, to a SQLAlchemy compatible database, or remotely to a tracking server. By default, the MLflow Python API logs runs locally to files in an mlruns directory wherever you ran your program. You can then run mlflow ui to see the logged runs.\nTo log runs remotely, set the MLFLOW_TRACKING_URI environment variable to a tracking server’s URI or call mlflow.set_tracking_uri().\nThere are different kinds of remote tracking URIs:\n Local file path (specified as file:/my/local/dir), where data is just directly stored locally. Database encoded as +://:@:/. MLflow supports the dialects mysql, mssql, sqlite, and postgresql. For more details, see SQLAlchemy database uri. HTTP server (specified as https://my-server:5000), which is a server hosting an MLflow tracking server. Databricks workspace (specified as databricks or as databricks://, a Databricks CLI profile. Refer to Access the MLflow tracking server from outside Databricks [AWS] [Azure], or the quickstart to easily get started with hosted MLflow on Databricks Community Edition.   We use sqlite for tracking. MLFLOW_TRACKING_URI=sqlite:///mlflow.db. This file stays at the root directory of the project.\n You can optionally organize runs into experiments, which group together runs for a specific task. You can create an experiment using the mlflow experiments CLI, with mlflow.create_experiment(), or using the corresponding REST parameters. The MLflow API and UI let you create and search for experiments.\n # setting env vars for minio artifact storage set_env_vars() mlflow.set_tracking_uri(os.getenv(\u0026quot;MLFLOW_TRACKING_URI\u0026quot;)) # creates a new mlflow experiment MLFLOW_EXPERIMENT_NAME if it doesn't exist exps = [exp.name for exp in mlflow.tracking.MlflowClient().list_experiments()] if not os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;) in exps: mlflow.create_experiment( os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;), artifact_location=os.getenv(\u0026quot;MLFLOW_ARTIFACT_LOCATION\u0026quot;), )  First time we execute the pipeline, experiment MLFLOW_EXPERIMENT_NAME=MLOps is created and is used for subsequent runs.\ndef train_and_validate_clf( X_train: np.array, X_test: np.array, y_train: np.array, y_test: np.array ) -\u0026gt; str: mlflow.set_experiment(os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;)) with mlflow.start_run(run_name=\u0026quot;NAIVE_BAYES_CLF\u0026quot;): # ignoring rest of the script pass  Registry # # Under an experiment, we can log metrics, log model parameters, save and version model artifacts. These steps come under the purview of model-registry. Here, we log\n classifier parameter alpha classification metrics precision, recall and f1_score  We also save and version the model using mlflow.sklearn.log_model. Each subsequent run of the pipeline with the same artifact_path and registered_model_name increases the model version by 1 in the registry.\ndef train_and_validate_clf( X_train: np.array, X_test: np.array, y_train: np.array, y_test: np.array ) -\u0026gt; str: mlflow.set_experiment(os.getenv(\u0026quot;MLFLOW_EXPERIMENT_NAME\u0026quot;)) with mlflow.start_run(run_name=\u0026quot;NAIVE_BAYES_CLF\u0026quot;): clf = MultinomialNB() mlflow.log_param(\u0026quot;alpha\u0026quot;, clf.get_params()[\u0026quot;alpha\u0026quot;]) clf.fit(X_train, y_train) y_pred = clf.predict(X_test) scores = precision_recall_fscore_support(y_test, y_pred, average=\u0026quot;weighted\u0026quot;) mlflow.log_metric(\u0026quot;precision\u0026quot;, scores[0]) mlflow.log_metric(\u0026quot;recall\u0026quot;, scores[1]) mlflow.log_metric(\u0026quot;f1_score\u0026quot;, scores[2]) mlflow.sklearn.log_model( sk_model=clf, artifact_path=\u0026quot;naive-bayes-model\u0026quot;, registered_model_name=\u0026quot;sk-learn-naive-bayes-clf-model\u0026quot;, ) return classification_report(y_test, y_pred)  Heading over to the experiment section at http://127.0.0.1:5000, we can see the registry entry for each of our runs, along with the logged metrics and model parameters.\n  For each run, we can also look at the artifact location.\n  When we created the experiment, we speficified artifact_location=os.getenv(\u0026quot;MLFLOW_ARTIFACT_LOCATION\u0026quot;) where MLFLOW_ARTIFACT_LOCATION=s3://mlflow. Internally, this stores the model artifacts locally at the directory minio_data we created during the setup.\nWe can head over to http://127.0.0.1:9001/buckets/mlflow/browse to look at the saved model artifacts.\n  In the next part, we will look at serving the trained model being a REST endpoint.\n"}).add({id:5,href:"/blog/mlops-template-part-2-dagster-pipeline/",title:"MLOps template [Part 2] · Dagster Pipeline",description:"Here we will cover our small pipeline written in dagster.",content:" Dagster is a data orchestrator for machine learning, analytics, and ETL\n Dagster is a second generation data orchestrator that focues on being data-driven rather than task-driven(like Airflow).\nSolids and Pipelines # #  Dagster\u0026rsquo;s core abstractions are solids and pipelines.\n  Solids are individual units of computation that we wire together to form pipelines. By default, all solids in a pipeline execute in the same process. In production environments, Dagster is usually configured so that each solid executes in its own process.\n Dataset # Our pipeline will operate on Question Type Classification. This data helps to classify the given Questions into respective categories based on what type of answer it expects such as a numerical answer or a text description or a place or human name etc.\n   Question Category     How did serfdom develop in and then leave Russia ? DESCRIPTION   What films featured the character Popeye Doyle ? ENTITY   How can I find a list of celebrities ' real names ? DESCRIPTION   What fowl grabs the spotlight after the Chinese Year of the Monkey ? ENTITY   What is the full form of .com ? ABBREVIATION   What contemptible scoundrel stole the cork from my lunch ? HUMAN   What team did baseball \u0026rsquo;s St. Louis Browns become ? HUMAN    Category can take following values - HUMAN, ENTITY, DESCRIPTION, NUMERIC, LOCATION.\nSolid # #  A solid is a unit of computation in a data pipeline. Typically, you\u0026rsquo;ll define solids by annotating ordinary Python functions with the @solid decorator.\n Our first solid get_training_dataset loads the data from csv and returns\n texts (List[str]) - Question target (List[str]) - Category  @solid( output_defs=[ OutputDefinition(name=\u0026quot;texts\u0026quot;, is_required=True), OutputDefinition(name=\u0026quot;target\u0026quot;, is_required=True), ] ) def get_training_dataset(context): texts, target = dataloaders.get_input_dataset(INPUT_DATASET_LOC) context.log.info(f\u0026quot;Loaded data; N={len(texts)}, Targets={set(target)}\u0026quot;) yield Output(texts, \u0026quot;texts\u0026quot;) yield Output(target, \u0026quot;target\u0026quot;)  OutputDefinition # #  To define multiple outputs, or to use a different output name than \u0026ldquo;result\u0026rdquo;, you can provide OutputDefinitions to the @solid decorator.\nWhen you have more than one output, you must yield an instance of the Output class to disambiguate between outputs.\n Let\u0026rsquo;s look at another solid preprocess_text.\n@solid def preprocess_text(context, texts): texts = text_preprocessing.preprocess_text(texts) context.log.info(f\u0026quot;Text pre-processing done; N={len(texts)}\u0026quot;) return texts  Here, we are doing some text preprocessing. Since we are not returning mulitple outputs here, we can avoid OutputDefinition.\nPipeline # #  To execute our solid, we\u0026rsquo;ll embed it in an equally simple pipeline. A pipeline is a set of solids arranged into a DAG of computation. You\u0026rsquo;ll typically define pipelines by annotating ordinary Python functions with the @pipeline decorator.\n Let\u0026rsquo;s look at our Pipeline.\n@pipeline def ml_pipeline(): # 1. fetch training data texts, target = get_training_dataset() # 2. minimal text preprocessing # 3. tfidf vectorization vectorizer, X = get_vectorizer_and_features(preprocess_text(texts)) # 4. target encoding target_encoder, encoded_target = get_targetencoder_and_encoded_targets(target) # 5. train test split X_train, X_test, y_train, y_test = train_test_split(X, encoded_target) # 6. model training, validation, registry, artifact storage train_clf(X_train, X_test, y_train, y_test)  Here we call few solids like get_training_dataset, preprocess_text, get_vectorizer_and_features, etc.\nThese calls don\u0026rsquo;t actually execute the solids. Within the bodies of functions decorated with @pipeline, we use function calls to indicate the dependency structure of the solids making up the pipeline.\nExecuting Our First Pipeline # # Dagit to visualize our pipeline in Dagit, from the directory in which we have saved the pipeline file.\n$ dagit -f mlops/pipeline.py # Loading repository... Serving on http://127.0.0.1:3000  We can head over to the browser and look at the pipeline.\n  To execute the pipeline from the UI, head over to the playground section and click Launch Execution (at the bottom right).\nIf the pipeline executed successfully, you should see logs like this.\n  The pipeline we just executed registered our trained model using MLflow and stored the model artifacts using minio.\nWe will look at those components in the next part.\n"}).add({id:6,href:"/blog/mlops-template-part-1-setup/",title:"MLOps template [Part 1] · Setup",description:"In this series of posts, we will take a small dataset and go through various steps like building Data pipelines, ML workflow management, API development and Monitoring.",content:"These steps are necessary for operationalization of any machine-learning based model.\nThese posts are in no way exhaustive in covering the breadth of MLOps.\nSeveral key pieces like the CI/CD pipeline, monitoring for drift, etc are missing at the moment, which might get added later.  Stack # We will be using the following tools in this project\n Data Pipeline: Dagster ML registry: MLflow API Development: FastAPI Monitoring: ElasticAPM  Dev Setup # Poetry # # $ curl -sSL https://raw.githubusercontent.com/python-poetry/poetry/master/get-poetry.py | python - $ poetry --version # Poetry version 1.1.10  pre-commit # # $ pip install pre-commit $ pre-commit --version # pre-commit 2.15.0  Minio # Follow the instructions here - Minio installation.\nFor Mac users\nbrew install minio/stable/minio  Install python packages # $ poetry install # Installing dependencies from lock file # No dependencies to install or update # Installing the current project: mlops (0.1.0)  MLflow # $ poetry shell $ export MLFLOW_S3_ENDPOINT_URL=http://127.0.0.1:9000 $ export AWS_ACCESS_KEY_ID=minioadmin $ export AWS_SECRET_ACCESS_KEY=minioadmin # make sure that the backend store and artifact locations are same in the .env file as well $ mlflow server \\ --backend-store-uri sqlite:///mlflow.db \\ --default-artifact-root s3://mlflow \\ --host 0.0.0.0    MinIO # $ export MINIO_ROOT_USER=minioadmin $ export MINIO_ROOT_PASSWORD=minioadmin $ mkdir minio_data $ minio server minio_data --console-address \u0026quot;:9001\u0026quot; # API: http://192.168.29.103:9000 http://10.119.80.13:9000 http://127.0.0.1:9000 # RootUser: minioadmin # RootPass: minioadmin # Console: http://192.168.29.103:9001 http://10.119.80.13:9001 http://127.0.0.1:9001 # RootUser: minioadmin # RootPass: minioadmin # Command-line: https://docs.min.io/docs/minio-client-quickstart-guide # $ mc alias set myminio http://192.168.29.103:9000 minioadmin minioadmin # Documentation: https://docs.min.io  Go to http://127.0.0.1:9001/buckets/ and create a bucket called mlflow.\n  Dagster # $ poetry shell $ dagit -f mlops/pipeline.py    ElasticAPM # $ docker-compose -f docker-compose-monitoring.yaml up    FastAPI # $ poetry shell $ export PYTHONPATH=. $ python mlops/app/application.py    "}),search.addEventListener('input',b,!0);function b(){var b,e;const d=5;b=this.value,e=a.search(b,{limit:d,enrich:!0});const c=new Map;for(const a of e.flatMap(a=>a.result)){if(c.has(a.doc.href))continue;c.set(a.doc.href,a.doc)}if(suggestions.innerHTML="",suggestions.classList.remove('d-none'),c.size===0&&b){const a=document.createElement('div');a.innerHTML=`No results for "<strong>${b}</strong>"`,a.classList.add("suggestion__no-results"),suggestions.appendChild(a);return}for(const[h,g]of c){const b=document.createElement('div');suggestions.appendChild(b);const a=document.createElement('a');a.href=h,b.appendChild(a);const e=document.createElement('span');e.textContent=g.title,e.classList.add("suggestion__title"),a.appendChild(e);const f=document.createElement('span');if(f.textContent=g.description,f.classList.add("suggestion__description"),a.appendChild(f),suggestions.appendChild(b),suggestions.childElementCount==d)break}}})()